"use client";
import { useRouter } from "next/navigation";
import { MOCK_MATCHES, MOCK_ADVISORS, type MockAdvisor, type MockMatch } from "@/lib/mock-data";
import { MessageSquare, Eye, FileSignature } from "lucide-react";

interface HydratedMatch { match: MockMatch; advisor: MockAdvisor }

// ─── Match row ────────────────────────────────────────────────────────────────

function MatchRow({ row, onMessage, onView, onContract }: { row: HydratedMatch; onMessage: () => void; onView: () => void; onContract: () => void }) {
  const a = row.advisor;
  const name = [a.firstName, a.lastName].filter(Boolean).join(" ");
  const initials = ((a.firstName?.[0] || "") + (a.lastName?.[0] || "")).toUpperCase();
  const tags = (a.selectedRoles || []).slice(0, 3);
  return (
    <div className="bg-white border border-gray-100 rounded-2xl p-5 hover:shadow-sm transition-all">
      <div className="flex items-start gap-4">
        <button onClick={onView} className="shrink-0">
          <div className="w-14 h-14 rounded-full bg-blue-600 text-white grid place-items-center font-bold text-lg">{initials}</div>
        </button>
        <button onClick={onView} className="min-w-0 flex-1 text-left">
          <div className="text-[15px] font-semibold text-gray-900 truncate">{name}</div>
          {a.headline && <div className="text-[13px] text-gray-500 line-clamp-2 mt-0.5">{a.headline}</div>}
          <div className="flex flex-wrap items-center gap-1.5 mt-2">
            {tags.map(t => <span key={t} className="text-[11px] font-medium px-2 py-0.5 rounded-full bg-blue-50 text-blue-700 border border-blue-100">{t}</span>)}
            {a.city && <span className="text-[12px] text-gray-400 ml-1">📍 {a.city}</span>}
            {a.hourlyRate && <span className="text-[12px] font-semibold text-gray-700 ml-1">${a.hourlyRate}/hr</span>}
          </div>
          {row.match.note && (
            <div className="mt-2 text-[12.5px] text-gray-500 italic line-clamp-2">&ldquo;{row.match.note}&rdquo;</div>
          )}
        </button>

        {/* Action buttons */}
        <div className="shrink-0 flex flex-col gap-2 items-end">
          <button onClick={onContract}
            className="flex items-center gap-1.5 px-4 py-2 bg-blue-600 text-white text-sm font-semibold rounded-xl hover:bg-blue-700 transition whitespace-nowrap">
            <FileSignature className="w-3.5 h-3.5" /> Send an offer
          </button>
          <div className="flex items-center gap-2">
            <button onClick={onView}
              className="flex items-center gap-1.5 px-3 py-1.5 border border-gray-200 text-gray-600 text-xs font-medium rounded-lg hover:bg-gray-50 transition">
              <Eye className="w-3.5 h-3.5" /> View details
            </button>
            <button onClick={onMessage}
              className="flex items-center gap-1.5 px-3 py-1.5 border border-gray-200 text-gray-600 text-xs font-medium rounded-lg hover:bg-gray-50 transition">
              <MessageSquare className="w-3.5 h-3.5" /> Message
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ─── Page ─────────────────────────────────────────────────────────────────────

export default function MatchedCXOPage() {
  const router = useRouter();

  const visible: HydratedMatch[] = MOCK_MATCHES
    .filter(m => m.status !== "archived")
    .map(m => ({ match: m, advisor: MOCK_ADVISORS[m.advisorUid] }))
    .filter(r => !!r.advisor);

  function goMessage(row: HydratedMatch) {
    router.push(`/dashboard/messages?thread=t_mock_${row.match.advisorUid}`);
  }

  function goProfile(row: HydratedMatch) {
    router.push(`/dashboard/advisor-profile?advisorId=${row.match.advisorUid}`);
  }

  function goSendOffer(row: HydratedMatch) {
    router.push(`/dashboard/send-offer?advisorId=${row.match.advisorUid}`);
  }

  return (
    <div>
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Matched CXO</h1>
        <p className="text-gray-500 text-sm mt-1">Executives our team has hand-picked for your needs. Reach out or start an engagement.</p>
      </div>
      <p className="text-xs text-gray-400 mb-3">{visible.length} match{visible.length === 1 ? "" : "es"}</p>
      <div className="flex flex-col gap-3">
        {visible.map(row => (
          <MatchRow
            key={row.match.id}
            row={row}
            onMessage={() => goMessage(row)}
            onView={() => goProfile(row)}
            onContract={() => goSendOffer(row)}
          />
        ))}
      </div>
    </div>
  );
}
